// Tools for abilities
function timer(execute, duration) {
    let timer = setInterval(() => execute(), 15.625);
    setTimeout(() => {
        clearInterval(timer);
    }, duration * 1000);
}

// Abilities n shit
function crit(me, them, multiplier, chance) {
    if (Math.floor(Math.random() * 101) + 1 < chance && (them.type == 'tank' || them.type == 'miniboss')) {
        me.damage *= multiplier * 2;
        me.source.sendMessage('Crit landed!');
        them.sendMessage(me.source + 'landed a critical hit on you!');
    }
}
function ice(them, multiplier, duration) {
    if (!them.immuneToAbilities && !them.invuln && !them.passive && !them.godmode) timer(() => {
        them.velocity.x /= multiplier;
        them.velocity.y /= multiplier;
    }, duration);
}
function poison(them, multiplier, duration) {
    if (!them.immuneToAbilities && !them.invuln && !them.passive && !them.godmode) timer(() => {
        if (them.health.amount > 10) them.health.amount -= multiplier * .1;
    }, duration);
}
function torch(me, them, multiplier, duration) {
    if (!them.immuneToAbilities && !them.invuln && !them.passive && !them.godmode && me.source.id !== them.source.id && me.team !== them.team) {
        poison(them, multiplier, duration);
        let theirOnDealtDamage = them.onDealtDamage || null;
        them.onDealtDamage = (me2, them2) => {
            torch(me2, them2, multiplier, duration);
            setTimeout(() => {
                me2.onDealtDamage = theirOnDealtDamage;
            }, duration * 1000);
        }
    }
}
function fireRandom(gun, gunInfo, bulletArr) {
    gun.bulletTypes = [bulletArr[Math.floor(Math.random() * bulletArr.length)]];
    gun.fire(...gunInfo);
}
function paralyze(them, duration) {
    if (!them.immuneToAbilities && !them.invuln && !them.passive && !them.godmode) timer(() => {
        them.velocity.x = 0;
        them.velocity.y = 0;
    }, duration);
}
function fireGun(gun) {
    gun.fire(
        gun.offset * Math.cos(gun.direction + gun.angle + gun.body.facing) + (1.35 * gun.length - gun.width * gun.settings.size / 2) * Math.cos(gun.angle + gun.body.facing),
        gun.offset * Math.sin(gun.direction + gun.angle + gun.body.facing) + (1.35 * gun.length - gun.width * gun.settings.size / 2) * Math.sin(gun.angle + gun.body.facing),
        gun.body.skill
    );
}

