function createSubmarine(options = {}) {
    if (options.time == null) {
        options.time = 1000;
    }
    defExport[options.name + "SubmarineTurret"] = {
        SHAPE: options.shape || 0,
        TRAVERSE_SPEED: .5
    }
    return {
        PARENT: [defExport.genericTank],
        LABEL: options.name,
        SIZE: defExport.genericTank.SIZE * 1.5 + 2 * options.tier,
        BODY: {
            HEALTH: 600 + 25 * options.tier,
            SPEED: 4 + .6 * options.tier
        },
        DANGER: options.tier + 6,
        SUBMARINE: options.time,
        SHAPE: options.shape || 0,
        HYDRO: options.hydro,
        FACING_TYPE: "smoothWithMotion",
        GUNS: (function() {
            const output = [];
            for (let i = 0; i < options.torpedoTubes.amount; i++) {
                output.push({
                    POSITION: [1, 3, 1, 0, 0, 0, i / options.torpedoTubes.amount / options.torpedoTubes.amount],
                    PROPERTIES: {
                        SHOOT_SETTINGS: combineStats([g.basic, g.submarineTorpedo, ...options.torpedoTubes.stats]),
                        TYPE: defExport.submarineTorpedo,
                        SET_SUBMERGED: true
                    }
                });
            }
            if (options.missileSilos) {
                for (let i = 0; i < options.missileSilos.amount; i++) {
                    const x = i / options.missileSilos.amount * 15 - 7.5;
                    output.push({
                        POSITION: [1, 3, 1, 0, x, 90, i / options.missileSilos.amount / options.missileSilos.amount / 2],
                        PROPERTIES: {
                            SHOOT_SETTINGS: combineStats([g.basic, g.submarineMissile, ...options.missileSilos.stats]),
                            TYPE: defExport.submarineMissile,
                            ALT_FIRE: true
                        }
                    }, {
                        POSITION: [1, 3, 1, 0, x, 270, i / options.missileSilos.amount / options.missileSilos.amount / 2],
                        PROPERTIES: {
                            SHOOT_SETTINGS: combineStats([g.basic, g.submarineMissile, ...options.missileSilos.stats]),
                            TYPE: defExport.submarineMissile,
                            ALT_FIRE: true
                        }
                    });
                }
            }
            return output;
        })(),
        TURRETS: [{
            POSITION: [8, 2, 0, 0, 0, 1],
            TYPE: defExport[options.name + "SubmarineTurret"]
        }]
    }
}
