function makeSanctuary(type) {
    let output = JSON.parse(JSON.stringify(type));
    output.PARENT = [defExport.dominator];
    output.LABEL = "Sanctuary";
    if (type.PARENT[0].FACING_TYPE) {
        output.FACING_TYPE = type.PARENT[0].FACING_TYPE;
    }
    output.GUNS = [defExport.dominator.GUNS || [], type.PARENT[0].GUNS || [], type.GUNS || []].flat();
    output.TURRETS = [defExport.dominator.TURRETS || [], type.PARENT[0].TURRETS || [], type.TURRETS || []].flat();
    output.TURRETS = output.TURRETS || [];
    output.TURRETS.push({
        POSITION: [8, 0, 0, 0, 360, 1],
        TYPE: defExport.sanctuaryTurret
    }, {
        POSITION: [8, 0, 0, 0, 360, 1],
        TYPE: [defExport.medicS, {
            CONTROLLERS: ["dontTurn"]
        }]
    });
    output.HITS_OWN_TYPE = "pushOnlyTeam";
    return output;
};
