function makeIron(type, name) {
    let output = structuredClone(type);
    output.ABILITY_IMMUNE = true;
    for (let i = 0; i < output.TURRETS.length; i++) {
        output.TURRETS[i].TYPE = [type.TURRETS[i].TYPE, {
            COLOR: 209
        }];
    }
    output.LABEL = name || 'Kevlar ' + output.LABEL;
    return output;
}
