for (const tank in defExport) {
    if (defExport[tank].GUNS instanceof Array) {
        defExport[tank].GUNS.forEach(gun => {
            if (gun.PROPERTIES && gun.PROPERTIES.SHOOT_SETTINGS) {
                const {
                    reload,
                    recoil,
                    shudder,
                    size,
                    health,
                    damage,
                    pen,
                    speed,
                    maxSpeed,
                    range,
                    density,
                    spray,
                    resist
                } = gun.PROPERTIES.SHOOT_SETTINGS;
                [recoil, shudder, speed, maxSpeed, range, spray].forEach(thing => {
                    if (!Number.isFinite(thing)) {
                        throw new Error("Invalid stats! defExport." + tank);
                    }
                });
            }
        });
    }
}
