function doLancerThing(my) {
    if (my.IS_SMASHER) {
        return;
    }
    my.IS_LANCER = true;
    for (let key in my) {
        if (key.startsWith("UPGRADES_TIER")) {
            my[key].forEach(doLancerThing);
        }
    }
}
doLancerThing(defExport.lancer);

function doSpikeThing(my) {
    my.HITS_OWN_TYPE = "spike";
    for (let key in my) {
        if (key.startsWith("UPGRADES_TIER")) {
            my[key].forEach(doSpikeThing);
        }
    }
}
doSpikeThing(defExport.spike);

